class Solution:
    def maxSpending(self, values):
        flat = sorted(v for row in values for v in row)
        return sum((i + 1) * v for i, v in enumerate(flat))

solutions.javascript:
var maxSpending = function(values) {
    const flat = [];
    for (const row of values) for (const v of row) flat.push(v);
    flat.sort((a, b) => a - b);
    let total = 0;
    for (let i = 0; i < flat.length; i++) total += (i + 1) * flat[i];
    return total;
};
